patch:
--- a/sync_fifo.sv
+++ b/sync_fifo.sv
@@ -1,10 +1,10 @@
 module sync_fifo #(parameter WIDTH = 8) (
     input clk,
     input rst_n,
     input [WIDTH-1:0] data_in,
     input write_en,
     output reg [WIDTH-1:0] data_out
 );
     reg [WIDTH-1:0] fifo_mem;
-    always @(posedge clk) begin
+    always @(posedge clk or negedge rst_n) begin
         if (!rst_n) begin
             data_out <= {WIDTH{1'b0}};
             fifo_mem <= {WIDTH{1'b0}};
         end else if (write_en) begin
             fifo_mem <= data_in;
             data_out <= fifo_mem;
         end
     end
 endmodule

before_code:
